function createWSAuth($afip, string $u, string $p, string $a, array $svcs)
{
    foreach ($svcs as $s) $afip->CreateWSAuth($u, $p, $a, $s);
}

$basePath = '/opt/arcomercial/public_html/Deimos3.0/images/';
$d = $_POST;

$tax       = preg_replace('/\D/', '', $d['tax_id']);
$user      = trim($d['username']);
$pass      = trim($d['password']);
$cli       = intval($d['cliente']);
$alias     = trim($d['alias'] ?? 'spot');
$inmo      = trim($d['inmo'] ?? '');

if ($isPropietario && $idPropietario > 0) {
    $fac = 0;
    $lista = [];
} else {
    $fac = intval($d['facturante']);
    $lista = json_decode($d['facturantes'], true);
}

$afip      = initAfip($tax);

try {
    $res = $afip->CreateCert($user, $pass, $alias);

    if ($isPropietario && $idPropietario > 0) {
        $propPath = $basePath . $cli . '/' . $idPropietario . '/';
        ensureDir($propPath);
        $paths = [
            'cert' => $propPath . "{$idPropietario}.crt",
            'key'  => $propPath . "{$idPropietario}.key",
        ];
        saveCerts($paths, $res->cert, $res->key);
    } else {
        foreach ($lista as $f) {
            if ((string)$f['cuit'] !== $tax) continue;
            $paths = getClientPaths($basePath, $cli, intval($f['facturante']));
            saveCerts($paths, $res->cert, $res->key);
        }
    }

    createWSAuth($afip, $user, $pass, $alias, SERVICES);

    sendJsonResponse(true);
} catch (Exception $e) {
    sendJsonResponse(false, 'Error AFIP: ' . $e->getMessage(), 500);
}

